public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // Build a realistic text payload (~5000 words)
        var words = new[]
        {
            "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
            "performance", "benchmarking", "infrastructure", "optimization",
            "a", "is", "an", "of", "to", "in", "for", "with",
            "extraordinarily", "computational", "implementation", "characteristics"
        };
        var rng = new Random(42);
        var parts = new string[5000];
        for (int i = 0; i < parts.Length; i++)
            parts[i] = words[rng.Next(words.Length)];
        _analyzer = new TextAnalyzer(string.Join(' ', parts));
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

