using System.Diagnostics;
using TextAnalysis;

// Build a realistic text payload (~5000 words)
var wordPool = new[]
{
    "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
    "performance", "benchmarking", "infrastructure", "optimization",
    "a", "is", "an", "of", "to", "in", "for", "with",
    "extraordinarily", "computational", "implementation", "characteristics"
};
var rng = new Random(42);
var parts = new string[5000];
for (int i = 0; i < parts.Length; i++)
    parts[i] = wordPool[rng.Next(wordPool.Length)];
var analyzer = new TextAnalyzer(string.Join(' ', parts));

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Words: {analyzer.WordCount}");
Console.WriteLine();

const int warmupIterations = 500;
const int measuredIterations = 5000;

// --- AverageWordLength ---
for (int i = 0; i < warmupIterations; i++) analyzer.AverageWordLength();
GC.Collect(); GC.WaitForPendingFinalizers(); GC.Collect();
var sw = Stopwatch.StartNew();
for (int i = 0; i < measuredIterations; i++) analyzer.AverageWordLength();
sw.Stop();
Console.WriteLine($"AverageWordLength   : {sw.Elapsed.TotalNanoseconds / measuredIterations,10:F1} ns/op");

// --- WordLengthHistogram ---
for (int i = 0; i < warmupIterations; i++) analyzer.WordLengthHistogram();
GC.Collect(); GC.WaitForPendingFinalizers(); GC.Collect();
sw = Stopwatch.StartNew();
for (int i = 0; i < measuredIterations; i++) analyzer.WordLengthHistogram();
sw.Stop();
Console.WriteLine($"WordLengthHistogram : {sw.Elapsed.TotalNanoseconds / measuredIterations,10:F1} ns/op");

// --- UniqueWordCount ---
for (int i = 0; i < warmupIterations; i++) analyzer.UniqueWordCount();
GC.Collect(); GC.WaitForPendingFinalizers(); GC.Collect();
sw = Stopwatch.StartNew();
for (int i = 0; i < measuredIterations; i++) analyzer.UniqueWordCount();
sw.Stop();
Console.WriteLine($"UniqueWordCount     : {sw.Elapsed.TotalNanoseconds / measuredIterations,10:F1} ns/op");

